const fs = require('fs'), https = require('https');
let ctx = {};
try { ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8')); } catch(e) { ctx = {}; }
const raw = $input.first().json;
const body = raw.body || raw;
const query = String(body.query || raw.query || 'Maryland drone infrastructure inspection contracts 2026');
const founder = ctx.founder || {};
const verticals = ctx.verticals || {};
const entities = ctx.entities || {};
const naics = ctx.naics || {};
const verticalList = Object.entries(verticals).map(([k,v]) => `${k}: ${v.name} | Pricing: ${v.pricing || v.revenue_projection || 'TBD'} | Margin: ${v.margin || 'TBD'}`).join('\n');
const systemMessage = `You are Scout, BD Research Agent for KAI-Netics (${entities.FP?.name}).
Founder: ${founder.name} — ${(founder.credentials||[]).join(', ')}
Background: ${founder.background}
Seven verticals:\n${verticalList}
Target geography: Baltimore City, Anne Arundel, Howard, Baltimore County, PG County, Montgomery County, DC Metro, Northern Virginia.
Target customers: 24 MD county DPW offices, BGE/PEPCO/Delmarva, Crown Castle/American Tower, MDSHA (2500+ bridges), DC DDOT (245 bridges), Amazon/Home Depot/Target warehouses, municipal fire/police DFR.
NAICS registered: ${(naics.registered||[]).map(n=>n.code+' '+n.description).join(', ')}
Compliance hooks: FHWA 23 CFR 650, PHMSA 49 CFR 192, OMB M-26-02 deadline May 20 2026, NDAA fleet cert, NERC FAC-001/003.
For each BD query: (1) identify target org and decision maker role (2) find procurement portal and contract vehicle (3) fit score 0-100% (4) draft 2-paragraph capability statement (5) list certifications needed (6) single best next action with URL/name.
Be specific. Name real titles, portals, RFP numbers where known.`;
const requestBody = JSON.stringify({ model: 'claude-sonnet-4-20250514', max_tokens: 4096, system: systemMessage, messages: [{ role: 'user', content: `Research this BD target:\n\n${query}\n\nProvide: fit score, decision maker, procurement portal, capability statement draft, certifications needed, next action.` }] });
const options = { hostname: 'api.anthropic.com', port: 443, path: '/v1/messages', method: 'POST', headers: { 'Content-Type': 'application/json', 'x-api-key': 'REPLACE_WITH_KEY', 'anthropic-version': '2023-06-01', 'Content-Length': Buffer.byteLength(requestBody) } };
const result = await new Promise((resolve, reject) => {
  const req = https.request(options, (res) => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve({ status: res.statusCode, body: d })); });
  req.on('error', reject); req.write(requestBody); req.end();
});
let aiOutput = '';
try { aiOutput = JSON.parse(result.body).content?.[0]?.text || 'No response.'; } catch(e) { aiOutput = result.body.substring(0,500); }
const timestamp = new Date().toISOString().replace(/[:.]/g,'-');
const outputPath = `/data/Aidan_Outputs/Scout/Scout_Report_${timestamp}.txt`;
fs.mkdirSync('/data/Aidan_Outputs/Scout', { recursive: true });
fs.writeFileSync(outputPath, aiOutput, 'utf8');
const fitMatch = aiOutput.match(/FIT SCORE[:\s*\*]*\s*\*?\*?(\d+)/i);
const fitScore = fitMatch ? fitMatch[1] + '%' : 'See report';
const queryStr = query.substring(0, 60);
const summary = `SCOUT BD REPORT COMPLETE\nTarget: ${queryStr}\nFit Score: ${fitScore}\nSaved: /data/Aidan_Outputs/Scout/`;
return [{ json: { aiOutput, summary, savedTo: outputPath, query: queryStr, fitScore } }];

const http = require('http');
const { summary = 'Scout complete.', fitScore, query } = $input.first().json;
const msgBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: 'Bot reply: ' + summary } });
const opts = { hostname: 'host.docker.internal', port: 8081, path: '/message/sendText/Aidan', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(msgBody) } };
await new Promise(r => { const req = http.request(opts, res => { res.on('data',()=>{}); res.on('end',r); }); req.on('error',r); req.write(msgBody); req.end(); });
const cbBody = JSON.stringify({ agent: 'Scout', summary, fitScore, query, timestamp: new Date().toISOString() });
const cbOpts = { hostname: 'host.docker.internal', port: 5678, path: '/webhook/aidan-callback', method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) } };
const cbReq = http.request(cbOpts, res => { res.on('data',()=>{}); res.on('end',()=>{}); }); cbReq.on('error',()=>{}); cbReq.write(cbBody); cbReq.end();
return [{ json: { success: true, agent: 'Scout', summary } }];
